    RAISE EXCEPTION '주식을 찾을 수 없습니다.';
  END IF;

  v_total_cost := v_stock_price * p_quantity;

  -- 학생 계좌 확인
  SELECT "accountId", "balance" INTO v_account_id, v_balance
  FROM accounts WHERE "userId" = p_user_id;

  IF v_balance < v_total_cost THEN
    RAISE EXCEPTION '잔액이 부족합니다.';
  END IF;

  -- 1. 학생 계좌에서 돈 차감
  UPDATE accounts SET balance = balance - v_total_cost WHERE "accountId" = v_account_id;

  -- 2. 거래 내역 기록
  INSERT INTO transactions ("accountId", type, amount, description, date)
  VALUES (v_account_id, 'StockBuy', -v_total_cost, v_stock_name || ' ' || p_quantity || '주 매수', now());

  -- 3. 학생 보유 주식 추가
  INSERT INTO student_stocks ("userId", "stockId", quantity, "purchasePrice")
  VALUES (p_user_id, p_stock_id, p_quantity, v_stock_price)
  ON CONFLICT ("userId", "stockId") 
  DO UPDATE SET 
    quantity = student_stocks.quantity + p_quantity,
    "purchasePrice" = (student_stocks."purchasePrice" * student_stocks.quantity + EXCLUDED."purchasePrice" * EXCLUDED.quantity) / (student_stocks.quantity + EXCLUDED.quantity);

  -- 4. 가격 변동 로직
  v_new_price := v_stock_price * (1 + (v_volatility * p_quantity));

  UPDATE "stock_products" SET "currentPrice" = v_new_price WHERE id = p_stock_id;

  RETURN '매수 완료! 주가가 상승했습니다.';
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 5. 매도 함수 업데이트 (수정됨: ID 파라미터 타입을 text로 변경)
CREATE OR REPLACE FUNCTION sell_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text AS $$
DECLARE
  v_stock_price int;
  v_total_earn int;
  v_account_id text;
  v_current_quantity int;
  v_volatility float;
  v_new_price int;
  v_stock_name text;
BEGIN
  -- 주식 정보 가져오기
  SELECT "currentPrice", "volatility", "name" INTO v_stock_price, v_volatility, v_stock_name
  FROM "stock_products" WHERE id = p_stock_id;

