  SELECT "accountId" INTO v_account_id
  FROM accounts WHERE "userId" = p_user_id;

  -- 1. 보유 주식 차감
  UPDATE student_stocks 
  SET quantity = quantity - p_quantity
  WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

