**문제 원인 분석:**

발생한 에러 `42P13: cannot change return type of existing function`은 기존에 이미 만들어져 있는 `buy_stock`이나 `sell_stock` 함수와 새로 만들려는 함수의 **설정(반환 타입 등)이 달라서** 덮어쓰지 못하겠다는 뜻입니다.

Supabase(PostgreSQL)에서는 안전을 위해 기존 함수를 완전히 삭제(`DROP`)하고 다시 생성하는 것이 가장 확실한 해결 방법입니다.

아래 **수정된 전체 SQL 쿼리**를 복사해서 Supabase SQL Editor에 다시 실행(Run)해 주세요. 기존 함수를 깨끗이 지우고 새로 생성하는 명령어가 포함되어 있습니다.

### 수정된 SQL 쿼리 (전체 복사 후 실행)

```sql
-- 1. 기존 함수들 삭제 (충돌 방지)
DROP FUNCTION IF EXISTS buy_stock(text, text, int);
DROP FUNCTION IF EXISTS buy_stock(uuid, uuid, int);
DROP FUNCTION IF EXISTS sell_stock(text, text, int);
DROP FUNCTION IF EXISTS sell_stock(uuid, uuid, int);

-- 2. 주식 종목 테이블에 '민감도(volatility)' 컬럼 추가
ALTER TABLE "stock_products" 
ADD COLUMN IF NOT EXISTS "volatility" float DEFAULT 0.01;

-- 3. 주식 차트용 가격 기록 테이블 생성 (stockId 타입을 text로 설정)
CREATE TABLE IF NOT EXISTS "stock_price_history" (
  "id" uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  "stockId" text REFERENCES "stock_products" ("id") ON DELETE CASCADE,
  "price" int NOT NULL,
  "createdAt" timestamptz DEFAULT now()
);

-- 4. 가격 변동 자동 기록 트리거 함수 생성
CREATE OR REPLACE FUNCTION log_stock_price_change()
RETURNS TRIGGER AS $$
BEGIN
  -- 가격(currentPrice)이 변경되었을 때만 실행
  IF NEW."currentPrice" <> OLD."currentPrice" THEN
    INSERT INTO "stock_price_history" ("stockId", "price")
    VALUES (NEW.id, NEW."currentPrice");
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 트리거 연결
DROP TRIGGER IF EXISTS on_stock_price_update ON "stock_products";
CREATE TRIGGER on_stock_price_update
  AFTER UPDATE ON "stock_products"
  FOR EACH ROW
  EXECUTE FUNCTION log_stock_price_change();

-- 5. 매수 함수 재생성 (가격 상승 로직 포함)
CREATE OR REPLACE FUNCTION buy_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text AS $$
DECLARE
  v_stock_price int;
  v_total_cost int;
  v_account_id text; 
  v_balance int;
  v_volatility float;
  v_new_price int;
  v_stock_name text;
BEGIN
  -- 정보 조회
  SELECT "currentPrice", "volatility", "name" INTO v_stock_price, v_volatility, v_stock_name
  FROM "stock_products" WHERE id = p_stock_id;

  IF v_stock_price IS NULL THEN
    RAISE EXCEPTION '주식을 찾을 수 없습니다.';
  END IF;

  v_total_cost := v_stock_price * p_quantity;

  -- 계좌 확인
  SELECT "accountId", "balance" INTO v_account_id, v_balance
  FROM accounts WHERE "userId" = p_user_id;

  IF v_balance < v_total_cost THEN
    RAISE EXCEPTION '잔액이 부족합니다.';
  END IF;

  -- 결제 및 거래 기록
  UPDATE accounts SET balance = balance - v_total_cost WHERE "accountId" = v_account_id;

  INSERT INTO transactions ("accountId", type, amount, description, date)
  VALUES (v_account_id, 'StockBuy', -v_total_cost, v_stock_name || ' ' || p_quantity || '주 매수', now());

  INSERT INTO student_stocks ("userId", "stockId", quantity, "purchasePrice")
  VALUES (p_user_id, p_stock_id, p_quantity, v_stock_price)
  ON CONFLICT ("userId", "stockId") 
  DO UPDATE SET 
    quantity = student_stocks.quantity + p_quantity,
    "purchasePrice" = (student_stocks."purchasePrice" * student_stocks.quantity + EXCLUDED."purchasePrice" * EXCLUDED.quantity) / (student_stocks.quantity + EXCLUDED.quantity);

  -- ★ 가격 변동 (상승): 민감도(없으면 기본 1%) 반영
  v_new_price := v_stock_price * (1 + (COALESCE(v_volatility, 0.01) * p_quantity));

  UPDATE "stock_products" SET "currentPrice" = v_new_price WHERE id = p_stock_id;

  RETURN '매수 완료! 주가가 상승했습니다.';
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 6. 매도 함수 재생성 (가격 하락 로직 포함)
CREATE OR REPLACE FUNCTION sell_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text AS $$
DECLARE
  v_stock_price int;
  v_total_earn int;
  v_account_id text;
  v_current_quantity int;
  v_volatility float;
  v_new_price int;
  v_stock_name text;
BEGIN
  -- 정보 조회
  SELECT "currentPrice", "volatility", "name" INTO v_stock_price, v_volatility, v_stock_name
  FROM "stock_products" WHERE id = p_stock_id;

  v_total_earn := v_stock_price * p_quantity;

  -- 보유 수량 확인
  SELECT quantity INTO v_current_quantity
  FROM student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

  IF v_current_quantity IS NULL OR v_current_quantity < p_quantity THEN
    RAISE EXCEPTION '보유 주식이 부족합니다.';
  END IF;

  SELECT "accountId" INTO v_account_id FROM accounts WHERE "userId" = p_user_id;

  -- 주식 차감 및 입금
  UPDATE student_stocks 
  SET quantity = quantity - p_quantity
  WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

  DELETE FROM student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id AND quantity <= 0;

  UPDATE accounts SET balance = balance + v_total_earn WHERE "accountId" = v_account_id;

  INSERT INTO transactions ("accountId", type, amount, description, date)
  VALUES (v_account_id, 'StockSell', v_total_earn, v_stock_name || ' ' || p_quantity || '주 매도', now());

  -- ★ 가격 변동 (하락): 민감도 반영
  v_new_price := v_stock_price * (1 - (COALESCE(v_volatility, 0.01) * p_quantity));

  IF v_new_price < 1 THEN
    v_new_price := 1;
  END IF;

  UPDATE "stock_products" SET "currentPrice" = v_new_price WHERE id = p_stock_id;

  RETURN '매도 완료! 주가가 하락했습니다.';
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

