### 2. Supabase SQL 업데이트 (필수)

자가 증식 방지 로직(수수료, 제한)을 DB 함수에 적용하기 위해 **아래 SQL 코드를 Supabase SQL Editor에 복사하여 반드시 실행(Run)**해 주세요.

```sql
-- 기존 함수 삭제 (충돌 방지)
DROP FUNCTION IF EXISTS buy_stock(text, text, int);
DROP FUNCTION IF EXISTS sell_stock(text, text, int);

-- 1. 매수 함수 재정의 (수량 제한, 보유 한도 제한 적용)
CREATE OR REPLACE FUNCTION buy_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text AS $$
DECLARE
  v_stock_price int;
  v_total_cost int;
  v_account_id text; 
  v_balance int;
  v_volatility float;
  v_new_price int;
  v_stock_name text;
  v_current_qty int;
BEGIN
  -- 1) 거래 수량 제한 (10주)
  IF p_quantity > 10 THEN
    RAISE EXCEPTION '한 번에 최대 10주까지만 거래할 수 있습니다.';
  END IF;

  -- 주식 정보 및 민감도 가져오기
  SELECT "currentPrice", "volatility", "name" INTO v_stock_price, v_volatility, v_stock_name
  FROM "stock_products" WHERE id = p_stock_id;

  IF v_stock_price IS NULL THEN
    RAISE EXCEPTION '주식을 찾을 수 없습니다.';
  END IF;

  -- 2) 보유 한도 제한 (50주) 확인
  SELECT quantity INTO v_current_qty
  FROM student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

  IF (COALESCE(v_current_qty, 0) + p_quantity) > 50 THEN
    RAISE EXCEPTION '한 종목당 최대 50주까지만 보유할 수 있습니다. (현재 %주 보유)', COALESCE(v_current_qty, 0);
  END IF;

  v_total_cost := v_stock_price * p_quantity;

  -- 학생 계좌 확인
  SELECT "accountId", "balance" INTO v_account_id, v_balance
  FROM accounts WHERE "userId" = p_user_id;

  IF v_balance < v_total_cost THEN
    RAISE EXCEPTION '잔액이 부족합니다.';
  END IF;

  -- 결제 및 거래 기록
  UPDATE accounts SET balance = balance - v_total_cost WHERE "accountId" = v_account_id;

  INSERT INTO transactions ("accountId", type, amount, description, date)
  VALUES (v_account_id, 'StockBuy', -v_total_cost, v_stock_name || ' ' || p_quantity || '주 매수', now());

  INSERT INTO student_stocks ("userId", "stockId", quantity, "purchasePrice")
  VALUES (p_user_id, p_stock_id, p_quantity, v_stock_price)
  ON CONFLICT ("userId", "stockId") 
  DO UPDATE SET 
    quantity = student_stocks.quantity + p_quantity,
    "purchasePrice" = (student_stocks."purchasePrice" * student_stocks.quantity + EXCLUDED."purchasePrice" * EXCLUDED.quantity) / (student_stocks.quantity + EXCLUDED.quantity);

  -- 가격 변동 (상승): 민감도(없으면 기본 1%) 반영
  v_new_price := v_stock_price * (1 + (COALESCE(v_volatility, 0.01) * p_quantity));

  UPDATE "stock_products" SET "currentPrice" = v_new_price WHERE id = p_stock_id;

  RETURN '매수 완료! 주가가 상승했습니다.';
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;


-- 2. 매도 함수 재정의 (수량 제한, 수수료 로직 F = 10k/(1+10k) 적용)
CREATE OR REPLACE FUNCTION sell_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text AS $$
DECLARE
  v_stock_price int;
  v_total_gross int; -- 수수료 전 총액
  v_fee_amount int;  -- 수수료
  v_final_earn int;  -- 최종 입금액
  v_account_id text;
  v_current_quantity int;
  v_volatility float;
  v_k float;         -- 민감도 변수
  v_fee_rate float;  -- 수수료율
  v_new_price int;
  v_stock_name text;
BEGIN
  -- 1) 거래 수량 제한 (10주)
  IF p_quantity > 10 THEN
    RAISE EXCEPTION '한 번에 최대 10주까지만 거래할 수 있습니다.';
  END IF;

  -- 정보 조회
  SELECT "currentPrice", "volatility", "name" INTO v_stock_price, v_volatility, v_stock_name
  FROM "stock_products" WHERE id = p_stock_id;

  v_total_gross := v_stock_price * p_quantity;

  -- 보유 수량 확인
  SELECT quantity INTO v_current_quantity
  FROM student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

  IF v_current_quantity IS NULL OR v_current_quantity < p_quantity THEN
    RAISE EXCEPTION '보유 주식이 부족합니다.';
  END IF;

  SELECT "accountId" INTO v_account_id FROM accounts WHERE "userId" = p_user_id;

  -- 2) 수수료 계산 로직
  -- k = 민감도 (기본값 0.01)
  v_k := COALESCE(v_volatility, 0.01);
  -- F = 10k / (1 + 10k)
  v_fee_rate := (10 * v_k) / (1 + (10 * v_k));
  -- 수수료 금액 (반올림)
  v_fee_amount := ROUND(v_total_gross * v_fee_rate)::int;
  -- 최종 입금액
  v_final_earn := v_total_gross - v_fee_amount;

  -- 주식 차감
  UPDATE student_stocks 
  SET quantity = quantity - p_quantity
  WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

  DELETE FROM student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id AND quantity <= 0;

  -- 계좌 입금 (수수료 차감된 금액)
  UPDATE accounts SET balance = balance + v_final_earn WHERE "accountId" = v_account_id;

  -- 거래 내역 기록 (수수료 정보 포함)
  INSERT INTO transactions ("accountId", type, amount, description, date)
  VALUES (v_account_id, 'StockSell', v_final_earn, v_stock_name || ' ' || p_quantity || '주 매도 (수수료 ' || v_fee_amount || '권 차감)', now());

  -- 가격 변동 (하락): 민감도 반영
  v_new_price := v_stock_price * (1 - (v_k * p_quantity));

  IF v_new_price < 1 THEN
    v_new_price := 1;
  END IF;

  UPDATE "stock_products" SET "currentPrice" = v_new_price WHERE id = p_stock_id;

  RETURN '매도 완료! (수수료 ' || v_fee_amount || '권 차감)';
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

**분석 결과:**

Supabase Security Advisor가 보고한 **"RLS Disabled in Public"** 에러는 보안상 매우 중요한 경고입니다.

*   **현재 상황:** 모든 테이블(`accounts`, `users`, `stock_products` 등)에 **RLS(Row Level Security, 행 단위 보안)** 가 설정되어 있지 않습니다.
*   **위험성:** 프론트엔드에서 사용하는 `anon key`는 공개되어 있습니다. RLS가 꺼져 있으면, 악의적인 사용자가 브라우저 콘솔을 통해 `supabase.from('users').delete()` 같은 명령어를 실행하여 **데이터를 전부 삭제하거나 조작할 수 있는 상태**입니다.
*   **해결 방법:** 모든 테이블에 RLS를 켜고(Enable), **"읽기(SELECT)"** 는 허용하되 **"쓰기/수정/삭제(INSERT/UPDATE/DELETE)"** 는 차단해야 합니다. 쓰기 작업은 우리가 만든 안전한 **함수(RPC)** 를 통해서만 이루어지도록 강제합니다.

