```sql
-- 1. 주식 차트용 기록 테이블 및 권한 재설정
CREATE TABLE IF NOT EXISTS "stock_price_history" (
  "id" uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  "stockId" text REFERENCES "stock_products" ("id") ON DELETE CASCADE,
  "price" int NOT NULL,
  "createdAt" timestamptz DEFAULT now()
);

-- RLS 정책 재설정 (읽기는 누구나, 쓰기는 보안 함수를 통해서만)
