  SELECT "accountId" INTO v_account_id FROM accounts WHERE "userId" = p_user_id;

  v_k := COALESCE(v_volatility, 0.01);
  v_fee_rate := (10 * v_k) / (1 + (10 * v_k));
  v_fee_amount := ROUND(v_total_gross * v_fee_rate)::int;
  v_final_earn := v_total_gross - v_fee_amount;

  UPDATE student_stocks SET quantity = quantity - p_quantity WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
  DELETE FROM student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id AND quantity <= 0;
  UPDATE accounts SET balance = balance + v_final_earn WHERE "accountId" = v_account_id;
  INSERT INTO transactions ("accountId", type, amount, description, date)
  VALUES (v_account_id, 'StockSell', v_final_earn, v_stock_name || ' ' || p_quantity || '주 매도 (수수료 ' || v_fee_amount || '권)', now());

  -- ★ 가격 하락 로직 (반올림 및 최소 1권 하락 보장)
  v_new_price := ROUND(v_stock_price * (1 - (v_k * p_quantity)));
  IF v_new_price >= v_stock_price THEN v_new_price := v_stock_price - 1; END IF;
  IF v_new_price < 1 THEN v_new_price := 1; END IF;

  UPDATE "stock_products" SET "currentPrice" = v_new_price WHERE id = p_stock_id;

  RETURN '매도 완료! (수수료 ' || v_fee_amount || '권 차감)';
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;
