-- 5. 펀드 가입(투자) 함수 (학생 -> 국고 이체 및 기록)
CREATE OR REPLACE FUNCTION join_fund(p_user_id text, p_fund_id uuid, p_units int)
RETURNS json AS $$
DECLARE
  v_fund RECORD;
  v_total_cost int;
  v_student_acc_id uuid;
  v_teacher_acc_id uuid;
  v_student_balance int;
BEGIN
  SELECT * INTO v_fund FROM funds WHERE id = p_fund_id;
  IF v_fund.status <> 'RECRUITING' THEN RAISE EXCEPTION '모집 기간이 아닙니다.'; END IF;

  v_total_cost := v_fund.unit_price * p_units;

  -- 학생 계좌 확인
  SELECT "accountId", "balance" INTO v_student_acc_id, v_student_balance FROM accounts WHERE "userId" = p_user_id;
  IF v_student_balance < v_total_cost THEN RAISE EXCEPTION '잔액이 부족합니다.'; END IF;

  -- 교사(국고) 계좌 확인
  SELECT "accountId" INTO v_teacher_acc_id FROM accounts WHERE "userId" = v_fund.teacher_id;

  -- 이체 실행
  UPDATE accounts SET balance = balance - v_total_cost WHERE "accountId" = v_student_acc_id;
  UPDATE accounts SET balance = balance + v_total_cost WHERE "accountId" = v_teacher_acc_id;

  -- 투자 기록
  INSERT INTO fund_investments (fund_id, student_user_id, units) VALUES (p_fund_id, p_user_id, p_units);

  -- 거래 내역
  INSERT INTO transactions ("accountId", type, amount, description, date)
  VALUES (v_student_acc_id, 'FundJoin', -v_total_cost, v_fund.name || ' 펀드 투자 (' || p_units || '좌)', now());

  RETURN json_build_object('success', true, 'message', '투자가 완료되었습니다.');
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;


-- 6. 펀드 정산 함수 (결과 처리)
CREATE OR REPLACE FUNCTION settle_fund(p_fund_id uuid, p_status text)
RETURNS json AS $$
DECLARE
  v_fund RECORD;
  v_inv RECORD;
  v_payout_per_unit int;
  v_total_payout int;
  v_total_invested int;
  v_creator_bonus int;
  v_teacher_acc_id uuid;
  v_student_acc_id uuid;
  v_msg text;
BEGIN
  SELECT * INTO v_fund FROM funds WHERE id = p_fund_id;
  IF v_fund.status = 'RECRUITING' THEN
    -- 강제 종료 시 ONGOING 거치지 않고 바로 정산 가능하도록 허용하거나 예외처리
    -- 여기서는 바로 진행
  END IF;

  -- 1. 상태별 지급액(1좌당) 계산
  IF p_status = 'SUCCESS' THEN
    v_payout_per_unit := v_fund.unit_price + v_fund.base_reward;
    v_msg := '목표 달성! 원금과 보상이 지급되었습니다.';
  ELSIF p_status = 'EXCEED' THEN
    v_payout_per_unit := v_fund.unit_price + v_fund.base_reward + v_fund.incentive_reward;
    v_msg := '초과 달성! 인센티브가 지급되었습니다.';
  ELSIF p_status = 'FAIL' THEN
    v_payout_per_unit := v_fund.unit_price - v_fund.base_reward;
    IF v_payout_per_unit < 0 THEN v_payout_per_unit := 0; END IF; -- 원금 이상의 손실 방지 (혹시 모를)
    v_msg := '목표 실패. 보상 차감 후 원금이 반환되었습니다.';
  ELSE
    RAISE EXCEPTION '잘못된 상태입니다.';
  END IF;

  -- 교사(국고) 계좌
  SELECT "accountId" INTO v_teacher_acc_id FROM accounts WHERE "userId" = v_fund.teacher_id;

  -- 2. 투자자들에게 정산금 지급
  FOR v_inv IN (SELECT * FROM fund_investments WHERE fund_id = p_fund_id) LOOP
    v_total_payout := v_inv.units * v_payout_per_unit;

    SELECT "accountId" INTO v_student_acc_id FROM accounts WHERE "userId" = v_inv.student_user_id;

    -- 국고 차감 / 학생 입금
    UPDATE accounts SET balance = balance - v_total_payout WHERE "accountId" = v_teacher_acc_id;
    UPDATE accounts SET balance = balance + v_total_payout WHERE "accountId" = v_student_acc_id;

    -- 거래 내역
    INSERT INTO transactions ("accountId", type, amount, description, date)
    VALUES (v_student_acc_id, 'FundPayout', v_total_payout, v_fund.name || ' 펀드 정산 (' || p_status || ')', now());
  END LOOP;

  -- 3. 제안자(Creator) 보너스 지급 (달성/초과달성 시에만)
  IF p_status IN ('SUCCESS', 'EXCEED') THEN
    -- 총 투자금 계산
    SELECT COALESCE(SUM(units) * v_fund.unit_price, 0) INTO v_total_invested FROM fund_investments WHERE fund_id = p_fund_id;

    IF v_total_invested > 0 THEN
      v_creator_bonus := v_total_invested * 0.1; -- 10%

      SELECT "accountId" INTO v_student_acc_id FROM accounts WHERE "userId" = v_fund.creator_student_id;

      UPDATE accounts SET balance = balance - v_creator_bonus WHERE "accountId" = v_teacher_acc_id;
      UPDATE accounts SET balance = balance + v_creator_bonus WHERE "accountId" = v_student_acc_id;

      INSERT INTO transactions ("accountId", type, amount, description, date)
      VALUES (v_student_acc_id, 'FundPayout', v_creator_bonus, v_fund.name || ' 펀드 운영 보너스 (10%)', now());
    END IF;
  END IF;

  -- 4. 펀드 상태 업데이트
  UPDATE funds SET status = p_status WHERE id = p_fund_id;

  RETURN json_build_object('success', true, 'message', v_msg);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

펀드 가입 시 발생하는 `invalid input syntax for type uuid: "권쌤은행 060103"` 에러는 **데이터베이스(SQL) 함수에서 텍스트 형식의 계좌번호("권쌤은행 ...")를 UUID 형식의 변수에 담으려고 할 때 발생하는 타입 불일치 오류**입니다.

이 문제를 해결하려면 **Supabase SQL Editor**에서 아래의 수정된 함수들을 실행하여 기존 함수를 덮어씌워야 합니다. (계좌 ID 변수 타입을 `uuid`에서 `text`로 변경했습니다.)

또한, 프론트엔드에서도 이러한 DB 오류 발생 시 원인을 더 명확히 파악할 수 있도록 `services/api.ts`의 에러 핸들링 로직을 보완하겠습니다.

