    const handleDeleteJob = async (jobId: string) => {
        if (!window.confirm('정말로 이 직업을 삭제하시겠습니까?')) return;
        try {
            const msg = await api.deleteJob(jobId);
            setMessageModal({ isOpen: true, type: 'success', message: msg });
