                            <MainAdminIcon className="w-32 h-32 mb-4 landscape:w-20 landscape:h-20 landscape:mb-2 md:landscape:w-44 md:landscape:h-44 md:landscape:mb-6"/>
                            {/* Text Size: Mobile (Small) -> Tablet (Large) */}
                            <span className="font-bold text-gray-800 text-xl landscape:text-sm md:landscape:text-2xl">교사 관리자</span>
