        setLoading(true);
        setError('');
        try {
            const user = await api.login(userId);
            if (user) {
                login(user);
            } else {
                setError('사용자를 찾을 수 없습니다.');
            }
        } catch (err) {
            setError('로그인 중 오류가 발생했습니다.');
        } finally {
            setLoading(false);
        }
    };

    const handleAppLogin = async () => {
        if (!grade || !cls || !num || !appPassword) {
            setError('모든 정보를 입력해주세요.');
            return;
