    useEffect(() => {
        fetchFunds();
    }, [fetchFunds]);

    const handleSettle = async (status: FundStatus) => {
        if (!settleModal.fund) return;
        try {
            const resultMsg = await api.settleFund(settleModal.fund.id, status);
            setMessageModal({ isOpen: true, type: 'success', message: resultMsg });
