                            <label className="block font-medium text-gray-700">투자 단위 금액 (1좌)</label>
                            <input type="number" name="unitPrice" value={formData.unitPrice} onChange={handleChange} className="w-full p-2 border rounded mt-1"/>
                        </div>
                         <div>
